import React from 'react'
import './ProjectBox.css'
import github from '../../Common/Vector.svg'

function ProjectBox({ Title, description, Link }) {
    // const elements = ['one', 'two', 'three'];

    const items = []

    for (const [index, value] of description.entries()) {
        items.push(<li key={index}><p>{value}</p></li>)
    }

    return (
        <div className='ProjectBox'>
            <h2>{Title}</h2>

            <ul>
                {items}
            </ul>

            <p><a href={Link}><img src={github} alt="github" /></a></p>

        </div>
    )
}

export default ProjectBox
